"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";
import {
  PaperPlaneTiltIcon,
  PhoneIcon,
  PhoneDisconnectIcon,
} from "@phosphor-icons/react";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

type ConnectionState = "disconnected" | "connecting" | "connected";

interface ConversationBarProps
  extends React.ComponentProps<"div">, VariantProps<typeof barVariants> {
  /** Called when the user sends a text message */
  onSend?: (message: string) => void;
  /** Called when the user presses connect */
  onConnect?: () => void;
  /** Called when the user presses disconnect */
  onDisconnect?: () => void;
  /** Current connection state. Default: "disconnected" */
  connectionState?: ConnectionState;
  /** Placeholder text for the input. Default: "Type a message…" */
  placeholder?: string;
  /** Whether to show the connection toggle button. Default: true */
  showConnectionToggle?: boolean;
  /** Whether the send button is disabled (e.g., while processing). Default: false */
  isSendDisabled?: boolean;
}

// =============================================================================
// VARIANTS
// =============================================================================

const barVariants = cva(
  "flex items-center gap-2 rounded-xl border border-border bg-background p-2 transition-colors focus-within:ring-2 focus-within:ring-ring focus-within:ring-offset-2 focus-within:ring-offset-background",
  {
    variants: {
      size: {
        sm: "p-1.5 gap-1.5",
        md: "p-2 gap-2",
        lg: "p-3 gap-3",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

const inputSizes = {
  sm: "text-sm px-2 py-1",
  md: "text-sm px-3 py-1.5",
  lg: "text-base px-3 py-2",
} as const;

const buttonSizes = {
  sm: "size-7",
  md: "size-8",
  lg: "size-10",
} as const;

const iconSizes = {
  sm: "size-3.5",
  md: "size-4",
  lg: "size-5",
} as const;

// =============================================================================
// CONNECTION STATUS INDICATOR
// =============================================================================

function StatusDot({ state }: { state: ConnectionState }) {
  return (
    <span
      className={cn(
        "size-2 rounded-full shrink-0",
        state === "connected" && "bg-green-500",
        state === "connecting" && "bg-yellow-500 animate-pulse",
        state === "disconnected" && "bg-muted-foreground/30"
      )}
      aria-hidden="true"
    />
  );
}

// =============================================================================
// COMPONENT
// =============================================================================

function ConversationBar({
  onSend,
  onConnect,
  onDisconnect,
  connectionState = "disconnected",
  placeholder = "Type a message…",
  showConnectionToggle = true,
  isSendDisabled = false,
  size,
  className,
  ...props
}: ConversationBarProps) {
  const [value, setValue] = React.useState("");
  const inputRef = React.useRef<HTMLInputElement>(null);

  const resolvedSize = size ?? "md";

  const handleSend = React.useCallback(() => {
    const trimmed = value.trim();
    if (!trimmed || isSendDisabled) return;
    onSend?.(trimmed);
    setValue("");
    inputRef.current?.focus();
  }, [value, isSendDisabled, onSend]);

  const handleKeyDown = React.useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        handleSend();
      }
    },
    [handleSend]
  );

  const handleConnectionToggle = React.useCallback(() => {
    if (connectionState === "connected") {
      onDisconnect?.();
    } else if (connectionState === "disconnected") {
      onConnect?.();
    }
  }, [connectionState, onConnect, onDisconnect]);

  return (
    <div
      data-slot="conversation-bar"
      data-connection={connectionState}
      className={cn(barVariants({ size }), className)}
      {...props}
    >
      {/* Connection toggle */}
      {showConnectionToggle && (
        <button
          type="button"
          onClick={handleConnectionToggle}
          disabled={connectionState === "connecting"}
          className={cn(
            "inline-flex items-center justify-center rounded-lg shrink-0 transition-colors",
            "focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-ring",
            buttonSizes[resolvedSize as keyof typeof buttonSizes],
            connectionState === "connected"
              ? "bg-destructive/10 text-destructive hover:bg-destructive/20"
              : "bg-primary/10 text-primary hover:bg-primary/20",
            connectionState === "connecting" && "opacity-50 cursor-not-allowed"
          )}
          aria-label={
            connectionState === "connected" ? "Disconnect" : "Connect"
          }
        >
          {connectionState === "connected" ? (
            <PhoneDisconnectIcon
              className={iconSizes[resolvedSize as keyof typeof iconSizes]}
              weight="fill"
            />
          ) : (
            <PhoneIcon
              className={iconSizes[resolvedSize as keyof typeof iconSizes]}
              weight="fill"
            />
          )}
        </button>
      )}

      {/* Status dot */}
      <StatusDot state={connectionState} />

      {/* Text input */}
      <input
        ref={inputRef}
        type="text"
        value={value}
        onChange={(e) => setValue(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder={placeholder}
        className={cn(
          "min-w-0 flex-1 bg-transparent outline-none placeholder:text-muted-foreground/50",
          inputSizes[resolvedSize as keyof typeof inputSizes]
        )}
        aria-label="Message input"
      />

      {/* Send button */}
      <button
        type="button"
        onClick={handleSend}
        disabled={!value.trim() || isSendDisabled}
        className={cn(
          "inline-flex items-center justify-center rounded-lg shrink-0 transition-colors",
          "focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-ring",
          "bg-primary text-primary-foreground hover:bg-primary/90",
          "disabled:opacity-40 disabled:cursor-not-allowed",
          buttonSizes[resolvedSize as keyof typeof buttonSizes]
        )}
        aria-label="Send message"
      >
        <PaperPlaneTiltIcon
          className={iconSizes[resolvedSize as keyof typeof iconSizes]}
          weight="fill"
        />
      </button>
    </div>
  );
}

ConversationBar.displayName = "ConversationBar";

export { ConversationBar, barVariants };
export type { ConversationBarProps, ConnectionState };
